import{_ as e}from"./chunks/project-settings_01.CuuUlwv5.js";import{_ as a,o,c as l,a2 as d}from"./chunks/framework.DnrXFDHb.js";const p=JSON.parse('{"title":"プロジェクト設定 (Project Settings)","description":"","frontmatter":{},"headers":[],"relativePath":"ja/configuration/project-settings.md","filePath":"ja/configuration/project-settings.md"}'),n={name:"ja/configuration/project-settings.md"};function s(r,t,i,c,g,h){return o(),l("div",null,[...t[0]||(t[0]=[d('<h1 id="プロジェクト設定-project-settings" tabindex="-1"><i class="ph-fill ph-gear-six"></i> プロジェクト設定 (Project Settings) <a class="header-anchor" href="#プロジェクト設定-project-settings" aria-label="Permalink to &quot;&lt;i class=&quot;ph-fill ph-gear-six&quot;&gt;&lt;/i&gt; プロジェクト設定 (Project Settings)&quot;">​</a></h1><p>すべてのグローバルなWebAP設定は、1つの場所に集中しています： <strong>Edit -&gt; Project Settings -&gt; Adaptive Performance (Web)</strong></p><p><img src="'+e+'" alt=""></p><h2 id="一般設定-general-settings" tabindex="-1">一般設定 (General Settings) <a class="header-anchor" href="#一般設定-general-settings" aria-label="Permalink to &quot;一般設定 (General Settings)&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">パラメータ</th><th style="text-align:left;">説明</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>Target Min FPS</strong></td><td style="text-align:left;">ベースラインとなるパフォーマンスの目標。 • 現在のFPSがこの値を下回った場合（パフォーマンスの余裕を考慮して）、プラグインはグラフィック品質の低下を開始します。 • FPSが継続してこの値を上回っている場合、プラグインは品質の向上を試みます。 <em>推奨事項:</em> 合理的な値を設定してください。WebGLの事実上の標準は <code>60</code> ですが、重い3Dプロジェクトの場合は <code>30</code> を利用できます。</td></tr></tbody></table><h2 id="インデクサー設定-indexer-settings" tabindex="-1">インデクサー設定 (Indexer Settings) <a class="header-anchor" href="#インデクサー設定-indexer-settings" aria-label="Permalink to &quot;インデクサー設定 (Indexer Settings)&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">パラメータ</th><th style="text-align:left;">説明</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>Decrease Cooldown</strong></td><td style="text-align:left;">品質を<em>下げた</em>後、システムがFPSを再評価するまでの待機時間（秒）。 <em>推奨事項:</em> 短く設定する必要があります（<code>1.0</code> - <code>2.0</code> 秒）。システムは遅延に機敏に反応し、FPSが安定するまで素早く負荷を軽減する必要があります。</td></tr><tr><td style="text-align:left;"><strong>Increase Cooldown</strong></td><td style="text-align:left;">品質を<em>上げた</em>後の待機時間。 <em>推奨事項:</em> 長く設定する必要があります（<code>5.0</code> - <code>10.0</code> 秒）。システムに再び負荷をかける前に、前回のグラフィック向上がフレームの安定性を損なっていないことを確認する必要があります。</td></tr></tbody></table><h2 id="アンチヨーヨー・ペナルティシステム-anti-yo-yo-penalty-system" tabindex="-1">アンチヨーヨー・ペナルティシステム (Anti Yo-Yo Penalty System) <a class="header-anchor" href="#アンチヨーヨー・ペナルティシステム-anti-yo-yo-penalty-system" aria-label="Permalink to &quot;アンチヨーヨー・ペナルティシステム (Anti Yo-Yo Penalty System)&quot;">​</a></h2><p>品質が2つのレベル間で際限なく交互に切り替わる「ヨーヨー効果」を防ぎます。</p><table tabindex="0"><thead><tr><th style="text-align:left;">パラメータ</th><th style="text-align:left;">説明</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>Detection Window</strong></td><td style="text-align:left;">品質を<em>上げた</em>後、システムがFPSを注意深く監視する時間枠。この期間中にFPSの低下が発生した場合、システムはそれをヨーヨー効果として分類します。</td></tr><tr><td style="text-align:left;"><strong>Penalty Lockout Duration</strong></td><td style="text-align:left;">品質を<em>上げよう</em>とする試みが断固としてブロックされるペナルティ期間（例：<code>60</code> 秒）。</td></tr></tbody></table><div class="info custom-block"><p class="custom-block-title">注記</p><p>ペナルティは増加のみをブロックします。FPSが再び低下した場合、システムは緊急手段として品質を低下させることができます。</p></div><h2 id="スケーラー-scalers" tabindex="-1">スケーラー (Scalers) <a class="header-anchor" href="#スケーラー-scalers" aria-label="Permalink to &quot;スケーラー (Scalers)&quot;">​</a></h2><p>アクティブな各スケーラーには、一連のベースラインパラメータがあります。これらのパラメータは、システムにとってのその「コスト」を指定します。プラグインはこのコストをリアルタイムで自動的に計算します。視覚的な影響が最も少なく、かつ該当するターゲット（CPU/GPU）に一致するスケーラーが優先的に実行されます。</p><table tabindex="0"><thead><tr><th style="text-align:left;">パラメータ</th><th style="text-align:left;">説明</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>Max Level</strong></td><td style="text-align:left;">ベース品質と最小品質の間の離散的なステップ（レベル）の数。たとえば、<code>Max Level = 4</code> は、このスケーラーに4段階の品質低下ステップがあることを意味します。</td></tr><tr><td style="text-align:left;"><strong>Min Bound</strong></td><td style="text-align:left;">最小スケール値（スケーラーが <code>Max Level</code> に達したときに適用されます）。たとえば、<code>0.5</code> は、品質が元の50%に低下することを示します。</td></tr><tr><td style="text-align:left;"><strong>Max Bound</strong></td><td style="text-align:left;">最大スケール値。通常は <code>1.0</code>（品質100%）と同じであり、レベル0のデフォルト値です。</td></tr><tr><td style="text-align:left;"><strong>Visual Impact</strong></td><td style="text-align:left;">レンダリングにおける視覚的な影響度（<code>Low</code>、<code>Medium</code>、<code>High</code>）。プラグインは、視覚的影響が <code>Low</code> のスケーラーに対して、体系的にレベルの増加（品質の低下）を優先します。</td></tr><tr><td style="text-align:left;"><strong>Target</strong></td><td style="text-align:left;">スケーラーが最適化するサブシステムを指定します（<code>CPU</code>、<code>GPU</code>、または両方）。現在のシステムボトルネックが <code>CPU</code> の場合、プラグインは <code>GPU</code> に焦点を当てたスケーラーを無視します。</td></tr><tr><td style="text-align:left;"><strong>Target Tags</strong></td><td style="text-align:left;">一部の専用スケーラー（<code>WebResolutionScaler</code>、<code>WebCameraClipScaler</code>、<code>WebLayerCullingScaler</code>）は、設定をグローバルに実行するのではなく、シーン内の特定のカメラに適用します。</td></tr></tbody></table><div class="warning custom-block"><p class="custom-block-title">カメラタグ (Camera Tags) の操作</p><p>これらのスケーラーは <code>Camera.main</code> 呼び出しを使用しません。代わりに、<code>Target Tags</code> 配列を使用してアクティブなカメラをスキャンします。</p><p>デフォルトでは、<code>MainCamera</code> タグがここで指定されています。<strong>ゲームがカスタムカメラタグ（例：<code>PlayerCamera</code>）を使用している場合は、それらをスケーラー設定に追加する必要があります。</strong> そうしないと、それらのカメラでスケーリングがトリガーされません。</p></div><h2 id="開発設定-development-settings" tabindex="-1">開発設定 (Development Settings) <a class="header-anchor" href="#開発設定-development-settings" aria-label="Permalink to &quot;開発設定 (Development Settings)&quot;">​</a></h2><p>このセクションは、ブラウザまたはエディターでのプラグインの動作のデバッグ専用です。</p><table tabindex="0"><thead><tr><th style="text-align:left;">パラメータ</th><th style="text-align:left;">説明</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>Logging</strong></td><td style="text-align:left;">プラグインの操作の詳細なトレースをブラウザ（またはUnity）コンソールに記録できます。ボトルネックの変化、スケーラーの有効化、およびアンチヨーヨーペナルティシステムの作動に関するメッセージを出力します。</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">最適化</p><p>ロギングには内部の <code>DebugWebAP</code> ラッパーが使用されます。リソースを節約し、コンソールをきれいに保つために、プロダクション（リリース）ビルドでは <code>Logging</code> オプションを無効にすることを強くお勧めします。</p></div>',19)])])}const f=a(n,[["render",s]]);export{p as __pageData,f as default};
